import{_ as n,C as o,o as l,c as s,E as r,w as a,a as t,a0 as d}from"./chunks/framework.CkNTPv-z.js";const w=JSON.parse('{"title":"Greece Legal Rights","description":"Legal rights for transgender people in Greece","frontmatter":{"layout":"doc","title":"Greece Legal Rights","description":"Legal rights for transgender people in Greece"},"headers":[],"relativePath":"europe/greece/legal-rights.md","filePath":"europe/greece/legal-rights.md","lastUpdated":null}'),c={name:"europe/greece/legal-rights.md"};function g(h,e,m,u,p,f){const i=o("Badge");return l(),s("div",null,[r(i,{variant:"yellow"},{default:a(()=>[...e[0]||(e[0]=[t("Medicalized (No Surgery)",-1)])]),_:1}),r(i,{variant:"green"},{default:a(()=>[...e[1]||(e[1]=[t("Anti-Discrimination Laws",-1)])]),_:1}),r(i,{variant:"yellow"},{default:a(()=>[...e[2]||(e[2]=[t("Hate Crime Protections",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="legal-rights-in-greece" tabindex="-1">Legal Rights in Greece <a class="header-anchor" href="#legal-rights-in-greece" aria-label="Permalink to &quot;Legal Rights in Greece&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>The <strong>Law 4491/2017</strong> reformed gender recognition in Greece:</p><ul><li><strong>Requirements</strong>: Diagnosis of gender dysphoria from a licensed psychiatrist or endocrinologist</li><li><strong>Surgery</strong>: Explicitly <strong>not required</strong> — this was a landmark change from pre-2017 law</li><li><strong>Age</strong>: 18+ can apply; 15-17 with parental consent and court approval</li><li><strong>Process</strong>: Application to the Civil Registry (Ληξιαρχείο) with medical certificate</li><li><strong>Timeframe</strong>: Typically 3-6 months</li></ul><h3 id="key-reform-details" tabindex="-1">Key Reform Details <a class="header-anchor" href="#key-reform-details" aria-label="Permalink to &quot;Key Reform Details&quot;">​</a></h3><ul><li>Law 4491/2017 removed the requirement for sex reassignment surgery</li><li>Also removed the requirement for sterilization (previously mandatory)</li><li>Still requires a medical diagnosis (gatekept by medical professionals)</li><li>Non-binary recognition is not explicitly provided for</li></ul><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Name change is processed alongside gender recognition at the Civil Registry</li><li>No separate medical requirements beyond those for gender recognition</li><li>Court decision required for minors</li><li>Typically processed within the same timeframe as gender marker change</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Greece has trans-inclusive anti-discrimination protections covering:</p><ul><li><strong>Employment</strong>: Law 4443/2016 prohibits discrimination based on gender identity</li><li><strong>Education</strong>: Equal access protections</li><li><strong>Healthcare</strong>: Cannot be denied treatment on the basis of gender identity</li><li><strong>Goods and Services</strong>: Protected under EU-derived legislation</li></ul><p>Enforcement is improving but remains inconsistent, especially outside Athens.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><ul><li>Gender identity is covered under hate crime legislation in the Greek Penal Code</li><li>The <strong>Racist Violence Recording Network</strong> monitors and reports incidents</li><li>Police have specialized departments for handling hate crimes in Athens and Thessaloniki</li><li>Prosecution rates are low but awareness is growing</li></ul><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Updated passports and ID cards are recognized internationally</li><li>Greek identity cards do not show gender explicitly (removed in 2020)</li><li>Passports show updated gender marker</li><li>Previous documents are sealed and not publicly accessible</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.moh.gov.gr/" target="_blank" rel="noreferrer">Greek Ministry of Health</a></li><li><a href="https://www.synthesis.gr/" target="_blank" rel="noreferrer">SYNTHESI (Trans Support)</a></li><li><a href="https://www.colouryouth.gr/" target="_blank" rel="noreferrer">Colour Youth</a></li><li><a href="https://rvrn.org/" target="_blank" rel="noreferrer">Racist Violence Recording Network</a></li></ul>',18))])}const b=n(c,[["render",g]]);export{w as __pageData,b as default};
